using UnityEngine;

/// <summary>
/// Corrente subaquática (Tarefa #14 — GDD "correntes" / "correnteza segura
/// até checkpoint"): zona de Collider2D (Trigger) que empurra players com
/// WaterMotor2D activo numa direcção constante enquanto estiverem dentro.
///
/// "isSafeCurrent" marca correntes que conduzem o jogador de volta a uma zona
/// segura/junto a um checkpoint (SafeHaven) — apenas informativo (para design
/// de nível e para outros sistemas, ex.: hazards que queiram ignorar o player
/// numa corrente segura).
///
/// Aplica a força mesmo que o movimento do player esteja bloqueado (ex.:
/// ShellGuard) — ver WaterMotor2D.AddCurrentForce.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class WaterCurrentZone : MonoBehaviour
{
    [Header("Força da Corrente")]
    [Tooltip("Direcção da corrente (normalizada internamente).")]
    public Vector2 forceDirection = Vector2.right;

    [Tooltip("Intensidade da força aplicada por segundo.")]
    public float forceStrength = 6f;

    [Header("Correnteza Segura (GDD)")]
    [Tooltip("Marca esta corrente como 'segura' (ex.: leva o jogador de volta a uma zona junto a um checkpoint/SafeHaven). Apenas informativo — não altera o comportamento da força em si.")]
    public bool isSafeCurrent = false;

    private void OnTriggerStay2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        var waterMotor = other.GetComponent<WaterMotor2D>();
        if (waterMotor == null || !waterMotor.IsActive) return;

        waterMotor.AddCurrentForce(forceDirection.normalized * forceStrength);
    }

    private void OnDrawGizmos()
    {
        var col = GetComponent<Collider2D>();
        if (col == null) return;

        Gizmos.color = isSafeCurrent
            ? new Color(0.3f, 0.6f, 1f, 0.35f)
            : new Color(0.2f, 0.85f, 1f, 0.35f);

        Gizmos.DrawCube(col.bounds.center, col.bounds.size);

        // Seta indicativa da direcção da corrente.
        Gizmos.color = Color.white;
        Vector3 center = col.bounds.center;
        Vector3 dir = ((Vector2)forceDirection).normalized;
        Gizmos.DrawLine(center, center + dir * 1.5f);
    }
}
